// components/ComparePane.tsx
import { useBreakpoint } from '@/hooks/useBreakpoint';
import { useRef, useEffect } from 'react';

export function ComparePane({ left, right }: { left: React.ReactNode; right: React.ReactNode }) {
  const bp = useBreakpoint();
  const leftRef = useRef<HTMLDivElement>(null);
  const rightRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (bp === 'mobile') return;
    let syncing = false;
    const sync = (from: HTMLDivElement, to: HTMLDivElement) => {
      if (syncing) return;
      syncing = true;
      to.scrollTop = from.scrollTop;
      requestAnimationFrame(() => { syncing = false; });
    };
    const l = leftRef.current!;
    const r = rightRef.current!;
    const onLeft = () => sync(l, r);
    const onRight = () => sync(r, l);
    l.addEventListener('scroll', onLeft);
    r.addEventListener('scroll', onRight);
    return () => { l.removeEventListener('scroll', onLeft); r.removeEventListener('scroll', onRight); };
  }, [bp]);

  if (bp === 'mobile') {
    return <div>{/* Tabs */}</div>;
  }

  return (
    <div className="grid grid-cols-2 divide-x h-dvh">
      <div ref={leftRef} className="overflow-y-auto">{left}</div>
      <div ref={rightRef} className="overflow-y-auto">{right}</div>
    </div>
  );
}

